SELECT task_name
FROM tasks
WHERE estimated_hours = (SELECT MAX(estimated_hours) FROM tasks);

SELECT p.project_name, t.task_name
FROM tasks t
JOIN projects p ON t.project_id = p.project_id
WHERE t.assigned_to NOT IN (
  SELECT user_id FROM users
);

SELECT project_name 
FROM projects 
WHERE budget = (
    SELECT MAX(budget) 
    FROM projects
);
